import{c as t,Q as o,j as s,m as a}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse('{"title":"The Decoder — 2026-05-26","description":"","frontmatter":{"title":"The Decoder — 2026-05-26","date":"2026-05-26T00:00:00.000Z","source":"The Decoder","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-26-the-decoder.md","filePath":"research/ai-news/2026-05/2026-05-26-the-decoder.md","lastUpdated":1779894392000}'),r={name:"research/ai-news/2026-05/2026-05-26-the-decoder.md"};function n(i,e,l,d,h,c){return o(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="🔓-the-decoder-—-2026-05-26" tabindex="-1">🔓 The Decoder — 2026-05-26 <a class="header-anchor" href="#🔓-the-decoder-—-2026-05-26" aria-label="Permalink to &quot;🔓 The Decoder — 2026-05-26&quot;">​</a></h1><blockquote><p>企業 AI 開發與模型應用日報，涵蓋 AI 社會影響（英語媒體） 來源：<a href="https://the-decoder.com/feed/" target="_blank" rel="noreferrer">The Decoder</a></p></blockquote><hr><h2 id="at-the-launch-of-pope-leo-xiv-s-encyclical-anthropic-co-founder-says-ai-models-show-signs-of-introspection" tabindex="-1"><a href="https://the-decoder.com/at-the-launch-of-pope-leo-xivs-encyclical-anthropic-co-founder-says-ai-models-show-signs-of-introspection/" target="_blank" rel="noreferrer">At the launch of Pope Leo XIV&#39;s encyclical, Anthropic co-founder says AI models show signs of introspection</a> <a class="header-anchor" href="#at-the-launch-of-pope-leo-xiv-s-encyclical-anthropic-co-founder-says-ai-models-show-signs-of-introspection" aria-label="Permalink to &quot;[At the launch of Pope Leo XIV&#39;s encyclical, Anthropic co-founder says AI models show signs of introspection](https://the-decoder.com/at-the-launch-of-pope-leo-xivs-encyclical-anthropic-co-founder-says-ai-models-show-signs-of-introspection/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-25</em></p><p>Anthropic co-founder Christopher Olah was invited to speak at the launch of Pope Leo XIV&#39;s encyclical &quot;Magnifica Humanitas&quot; and used the stage to claim AI models show evidence of introspection and emotion-like states. The Pope&#39;s own document struck a different tone: &quot;These systems merely imitate certain functions of human intelligence.&quot;</p><p>The article <a href="https://the-decoder.com/at-the-launch-of-pope-leo-xivs-encyclical-anthropic-co-founder-says-ai-models-show-signs-of-introspection/" target="_blank" rel="noreferrer">At the launch of Pope Leo XIV&#39;s encyclical, Anthropic co-founder says AI models show signs of introspection</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="google-deepmind-s-alphaproof-nexus-solves-decades-old-math-problems-for-a-few-hundred-dollars" tabindex="-1"><a href="https://the-decoder.com/google-deepminds-alphaproof-nexus-solves-decades-old-math-problems-for-a-few-hundred-dollars/" target="_blank" rel="noreferrer">Google Deepmind&#39;s AlphaProof Nexus solves decades-old math problems for a few hundred dollars</a> <a class="header-anchor" href="#google-deepmind-s-alphaproof-nexus-solves-decades-old-math-problems-for-a-few-hundred-dollars" aria-label="Permalink to &quot;[Google Deepmind&#39;s AlphaProof Nexus solves decades-old math problems for a few hundred dollars](https://the-decoder.com/google-deepminds-alphaproof-nexus-solves-decades-old-math-problems-for-a-few-hundred-dollars/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-25</em></p><p>Google Deepmind&#39;s AlphaProof Nexus has autonomously solved nine open Erdős problems, including two that stumped mathematicians for 56 years, for just a few hundred dollars per problem in inference costs. Unlike OpenAI&#39;s natural-language approach, the system uses the Lean compiler to verify every proof step automatically. Still, the overall success rate sits at just 2.5 percent.</p><p>The article <a href="https://the-decoder.com/google-deepminds-alphaproof-nexus-solves-decades-old-math-problems-for-a-few-hundred-dollars/" target="_blank" rel="noreferrer">Google Deepmind&#39;s AlphaProof Nexus solves decades-old math problems for a few hundred dollars</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="george-hotz-says-coding-agents-will-be-one-of-the-most-costly-mistakes-in-software-development" tabindex="-1"><a href="https://the-decoder.com/george-hotz-says-coding-agents-will-be-one-of-the-most-costly-mistakes-in-software-development/" target="_blank" rel="noreferrer">George Hotz says coding agents will be &quot;one of the most costly mistakes&quot; in software development</a> <a class="header-anchor" href="#george-hotz-says-coding-agents-will-be-one-of-the-most-costly-mistakes-in-software-development" aria-label="Permalink to &quot;[George Hotz says coding agents will be &quot;one of the most costly mistakes&quot; in software development](https://the-decoder.com/george-hotz-says-coding-agents-will-be-one-of-the-most-costly-mistakes-in-software-development/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-25</em></p><p>Programmer George Hotz warns that AI coding agents will become one of the industry&#39;s most costly mistakes. After six months of testing, his verdict: LLMs deliver fast prototypes but fall apart on the details, producing bugs that keep getting harder to spot. His stance is one example of how deeply split the AI community is over the role of LLMs.</p><p>The article <a href="https://the-decoder.com/george-hotz-says-coding-agents-will-be-one-of-the-most-costly-mistakes-in-software-development/" target="_blank" rel="noreferrer">George Hotz says coding agents will be &quot;one of the most costly mistakes&quot; in software development</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="ai-models-often-give-the-right-answers-but-point-to-the-wrong-sources" tabindex="-1"><a href="https://the-decoder.com/ai-models-often-give-the-right-answers-but-point-to-the-wrong-sources/" target="_blank" rel="noreferrer">AI models often give the right answers but point to the wrong sources</a> <a class="header-anchor" href="#ai-models-often-give-the-right-answers-but-point-to-the-wrong-sources" aria-label="Permalink to &quot;[AI models often give the right answers but point to the wrong sources](https://the-decoder.com/ai-models-often-give-the-right-answers-but-point-to-the-wrong-sources/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-25</em></p><p>Leading AI models like GPT and Gemini routinely cite text passages in document analyses that don&#39;t actually support their answers. Even when the answer is right, the cited evidence is often wrong. Researchers at Peking University call this &quot;attribution hallucination,&quot; a risk for regulated fields like law and medicine. Their new CiteVQA benchmark is the first to test for it systematically.</p><p>The article <a href="https://the-decoder.com/ai-models-often-give-the-right-answers-but-point-to-the-wrong-sources/" target="_blank" rel="noreferrer">AI models often give the right answers but point to the wrong sources</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="bytedance-study-finds-that-asking-lmms-questions-beats-making-it-transcribe-text-for-long-document-training" tabindex="-1"><a href="https://the-decoder.com/bytedance-study-finds-that-asking-lmms-questions-beats-making-it-transcribe-text-for-long-document-training/" target="_blank" rel="noreferrer">ByteDance study finds that asking LMMs questions beats making it transcribe text for long document training</a> <a class="header-anchor" href="#bytedance-study-finds-that-asking-lmms-questions-beats-making-it-transcribe-text-for-long-document-training" aria-label="Permalink to &quot;[ByteDance study finds that asking LMMs questions beats making it transcribe text for long document training](https://the-decoder.com/bytedance-study-finds-that-asking-lmms-questions-beats-making-it-transcribe-text-for-long-document-training/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-24</em></p><p>ByteDance Seed shows that a 7B model can answer questions on long, image-heavy documents more reliably than much larger models, even when documents are four times longer than anything it saw during training. Instead of transcribing pages, the model learns by answering questions and finding the right passages on its own.</p><p>The article <a href="https://the-decoder.com/bytedance-study-finds-that-asking-lmms-questions-beats-making-it-transcribe-text-for-long-document-training/" target="_blank" rel="noreferrer">ByteDance study finds that asking LMMs questions beats making it transcribe text for long document training</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr>',28)])])}const f=t(r,[["render",n]]);export{m as __pageData,f as default};
